                          <div className="relative">
                            <textarea value={metadata.observations} onChange={e => setMetadata({...metadata, observations: e.target.value})} className="w-full bg-gray-50 p-3 rounded-xl font-medium text-sm min-h-[100px]" />
                            <button onClick={handleImproveText} disabled={isImprovingText} className="absolute bottom-2 right-2 p-2 bg-black text-white rounded-lg text-[9px] font-black uppercase tracking-widest hover:bg-brand transition-all">
                               {isImprovingText ? 'Melhorando...' : '✨ IA Refine'}
