                 {activeTab === 'solutions' && (
                    <div className="space-y-4 animate-in fade-in duration-300">
                       {proposalItems.length === 0 ? (
                          <div className="text-center py-20 text-gray-400 text-[10px] font-black uppercase tracking-widest">Nenhuma solução selecionada.</div>
                       ) : proposalItems.map((item, idx) => (
                          <div key={idx} className="p-4 bg-gray-50 rounded-2xl border border-gray-100 flex justify-between items-center">
                             <div>
                                <h4 className="font-black text-gray-900 text-sm">{item.name}</h4>
                                <span className="text-[9px] font-bold text-gray-400 uppercase">{item.duration}</span>
                             </div>
                             <span className="font-mono text-xs font-bold">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(item.totalPrice)}</span>
                          </div>
                       ))}
                    </div>
                 )}

                 {activeTab === 'mapping' && (
                    <div className="space-y-6 animate-in fade-in duration-300">
                       <button 
                        onClick={handleGenerateAI} 
                        disabled={isGeneratingAI}
                        className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-blue-700 transition-all flex items-center justify-center gap-2"
                       >
                         {isGeneratingAI ? 'Analisando Mercado...' : '🔍 Gerar Mapeamento IA'}
