                       <div className="space-y-4">
                          {strategicMap.map((map, i) => (
                             <div key={i} className="p-4 bg-gray-50 rounded-2xl border border-gray-100 grid grid-cols-2 gap-4">
                                <div>
                                   <label className="text-[8px] font-black text-red-400 uppercase">Atual</label>
                                   <textarea value={map.current} onChange={e => {
                                      const newMap = [...strategicMap];
                                      newMap[i].current = e.target.value;
                                      setStrategicMap(newMap);
                                   }} className="w-full bg-transparent text-[11px] font-bold outline-none resize-none" rows={2} />
                                </div>
                                <div className="border-l border-gray-200 pl-4">
                                   <label className="text-[8px] font-black text-green-500 uppercase">Desejado</label>
                                   <textarea value={map.desired} onChange={e => {
                                      const newMap = [...strategicMap];
                                      newMap[i].desired = e.target.value;
                                      setStrategicMap(newMap);
                                   }} className="w-full bg-transparent text-[11px] font-bold outline-none resize-none" rows={2} />
                                </div>
                             </div>
                          ))}
                       </div>
                    </div>
                 )}

                 {activeTab === 'history' && (
                    <div className="space-y-4 animate-in fade-in duration-300">
                       {proposalHistory.map((h) => (
                          <div key={h.id} className="p-4 bg-gray-50 rounded-2xl border border-gray-100 flex justify-between items-center group hover:bg-white hover:shadow-md transition-all">
                             <div>
                                <h4 className="font-black text-gray-900 text-sm">{h.client_name}</h4>
                                <span className="text-[9px] font-bold text-gray-400 uppercase">{new Date(h.created_at).toLocaleDateString()}</span>
                             </div>
                             <div className="text-right">
                                <span className="block font-mono text-xs font-bold">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(h.total_value)}</span>
                                <button onClick={() => {
                                   setMetadata(h.metadata);
                                   setProposalItems(h.items);
                                   setActiveTab('info');
                                }} className="text-[8px] font-black text-blue-600 uppercase opacity-0 group-hover:opacity-100">Carregar</button>
                             </div>
                          </div>
                       ))}
                    </div>
                 )}
              </div>

              <div className="p-8 bg-black text-white space-y-6">
                 <div className="flex justify-between items-end">
                    <div>
                       <span className="text-[10px] font-black text-white/40 uppercase tracking-widest">Total Líquido</span>
                       <h3 className="text-3xl font-black">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(finalTotal)}</h3>
                    </div>
                    <div className="text-right">
                       <span className="text-[10px] font-black text-white/40 uppercase tracking-widest">Desconto</span>
                       <div className="flex items-center gap-2">
                          <input type="number" value={metadata.discountValue} onChange={e => setMetadata({...metadata, discountValue: parseFloat(e.target.value) || 0})} className="w-20 bg-white/10 text-right p-1 rounded font-bold text-sm outline-none" />
                          <select value={metadata.discountType} onChange={e => setMetadata({...metadata, discountType: e.target.value as any})} className="bg-white/10 p-1 rounded font-bold text-[10px] outline-none">
                             <option value="fixed">R$</option>
                             <option value="percentage">%</option>
