                       </div>
                    </div>
                 </div>
                 <button onClick={handleSaveProposal} disabled={isSaving} className="w-full py-5 bg-white text-black rounded-2xl font-black text-xs uppercase tracking-widest hover:scale-105 transition-all">
                    {isSaving ? 'Salvando...' : '💾 Salvar no Histórico'}
                  </button>
              </div>
           </div>
        </div>

        <div className="lg:col-span-7 space-y-8 flex flex-col h-full">
           <div className="flex items-center justify-between px-4">
              <div className="flex gap-4">
                <button onClick={() => setZoom(z => Math.max(0.3, z - 0.1))} className="p-3 bg-white border border-gray-100 rounded-xl hover:bg-black hover:text-white transition-all">－</button>
                <button onClick={() => setZoom(z => Math.min(1, z + 0.1))} className="p-3 bg-white border border-gray-100 rounded-xl hover:bg-black hover:text-white transition-all">＋</button>
              </div>
              <button onClick={() => window.print()} className="px-8 py-3 bg-black text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-brand transition-all flex items-center gap-2">
                <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path d="M5 4a2 2 0 012-2h6a2 2 0 012 2v14l-5-2.5L5 18V4z"/></svg> Imprimir / PDF
              </button>
           </div>

           <div className="flex-1 bg-gray-200 rounded-[40px] border border-gray-300 p-10 overflow-auto flex justify-center custom-scrollbar relative">
              {!isPreviewReady ? (
                 <div className="flex flex-col items-center justify-center space-y-4">
                    <div className="w-10 h-10 border-4 border-black border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Renderizando Preview...</span>
                 </div>
              ) : (
                <div style={{ transform: `scale(${zoom})`, transformOrigin: 'top center', width: '210mm' }} className="proposal-container no-print transition-transform duration-300">
                    <ProposalPresentation 
                      metadata={metadata}
                      items={proposalItems}
                      strategicMap={strategicMap}
                      appConfig={appConfig}
                      selectedSections={selectedSections}
                    />
                </div>
              )}
           </div>
        </div>
      </div>
    </div>
  );
};

