import React, { useState, useMemo, useRef } from 'react';

interface Slide {
  id: number;
  type: 'cover' | 'content' | 'tip' | 'cta';
  title: string;
  content: string[];
  accentText?: string;
}

const CarouselGenerator: React.FC = () => {
  const [inputText, setInputText] = useState<string>(
    "Slide 1: O *Segredo* do Crescimento\nComo empresas escalam sem quebrar.\n\nSlide 2: A Dor da Inércia\nFicar parado custa caro.\n- Perda de Market Share\n- Time Desmotivado\n- Margem Esmagada\n\nSlide 3: Dica de Ouro\nFoque no ROI, não no ego.\n\nSlide 4: Vamos Conversar?\nResponda 'MOVIMENTO' para começar."
  );

  const [activeSlide, setActiveSlide] = useState(0);

  const slides = useMemo(() => {
    const blocks = inputText.split(/Slide \d+:/i).filter(b => b.trim());
    return blocks.map((block, index): Slide => {
      const lines = block.trim().split('\n').filter(l => l.trim());
      const title = lines[0] || '';
      const content = lines.slice(1);

      let type: Slide['type'] = 'content';
      if (index === 0) type = 'cover';
      else if (index === blocks.length - 1) type = 'cta';
      else if (title.toLowerCase().includes('dica') || title.toLowerCase().includes('tip')) type = 'tip';

      // Extração de destaque (entre asteriscos)
      const accentMatch = title.match(/\*(.*?)\*/);
      const cleanTitle = title.replace(/\*/g, '');

      return {
        id: index + 1,
        type,
        title: cleanTitle,
        content,
        accentText: accentMatch ? accentMatch[1] : undefined
      };
    });
  }, [inputText]);

  const renderSlide = (slide: Slide) => {
    const commonClasses = "w-full aspect-square bg-white shadow-2xl rounded-[40px] flex flex-col p-16 relative overflow-hidden animate-in zoom-in-95 duration-500";

    // Processamento de texto com destaque
    const highlightTitle = (text: string, accent?: string) => {
      if (!accent) return text;
      const parts = text.split(accent);
      return (
        <>
          {parts[0]}
          <span className="text-blue-600 italic underline decoration-blue-200">{accent}</span>
          {parts[1]}
        </>
      );
    };

    if (slide.type === 'cover') {
      return (
        <div className={`${commonClasses} justify-center bg-gray-900 text-white`}>
           <div className="absolute top-10 left-10 w-12 h-1 bg-blue-600"></div>
           <h2 className="text-6xl font-black tracking-tighter leading-[0.9] uppercase italic">
             {highlightTitle(slide.title, slide.accentText)}
           </h2>
           <p className="mt-8 text-xl font-medium text-gray-400 max-w-xs">{slide.content[0]}</p>
           <div className="absolute bottom-16 left-16 flex items-center gap-4">
              <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-black">P</div>
              <span className="text-[10px] font-black uppercase tracking-[0.3em] opacity-40">PhantLab Content</span>
           </div>
        </div>
      );
    }

    if (slide.type === 'tip') {
      return (
        <div className={`${commonClasses} justify-between bg-blue-600 text-white`}>
           <div className="space-y-4">
              <span className="text-[10px] font-black uppercase tracking-[0.4em] opacity-60">Insight Prático</span>
              <h2 className="text-5xl font-black tracking-tighter leading-none italic">{slide.title}</h2>
           </div>
           <div className="bg-white/10 p-10 rounded-[40px] backdrop-blur-xl border border-white/10">
              <p className="text-2xl font-bold leading-relaxed italic">"{slide.content[0]}"</p>
           </div>
           <div className="text-[10px] font-black uppercase tracking-widest opacity-40 text-right">#EstratégiaPhant</div>
        </div>
      );
    }

    if (slide.type === 'cta') {
      return (
        <div className={`${commonClasses} justify-center items-center text-center space-y-12`}>
           <div className="w-24 h-24 bg-gray-50 rounded-[40px] flex items-center justify-center text-5xl">🤝</div>
           <div className="space-y-4">
              <h2 className="text-4xl font-black tracking-tighter uppercase italic">{slide.title}</h2>
              <p className="text-xl text-gray-500 font-medium max-w-sm mx-auto">{slide.content[0]}</p>
           </div>
           <button className="px-10 py-5 bg-black text-white rounded-[30px] font-black text-xs uppercase tracking-widest shadow-2xl">Enviar Mensagem</button>
        </div>
      );
    }

    // Default Content Slide
    return (
      <div className={commonClasses}>
         <div className="flex justify-between items-start mb-12">
            <h2 className="text-4xl font-black tracking-tighter italic text-gray-900 leading-none">{slide.title}</h2>
            <span className="text-4xl font-black text-gray-100 italic">0{slide.id}</span>
         </div>
         <div className="space-y-6 flex-1">
            {slide.content.map((line, i) => (
              <div key={i} className="flex items-start gap-4 animate-in slide-in-from-left duration-500" style={{ animationDelay: `${i * 100}ms` }}>
                 <div className="w-2 h-2 rounded-full bg-blue-600 mt-2 shrink-0"></div>
                 <p className="text-lg font-bold text-gray-600 leading-tight">{line.replace(/^- /, '')}</p>
              </div>
            ))}
         </div>
         <div className="pt-8 border-t border-gray-50 text-[9px] font-black text-gray-300 uppercase tracking-[0.3em]">
            Deslize para o lado →
         </div>
      </div>
    );
  };

  return (
    <div className="max-w-7xl mx-auto space-y-12 animate-in fade-in duration-700 px-4">
      <header className="flex flex-col md:flex-row justify-between items-end gap-6">
        <div>
          <h1 className="text-5xl font-black text-gray-900 tracking-tighter">Gerador de Carrosséis</h1>
          <p className="text-gray-400 text-lg font-medium mt-2">Cole seu roteiro e materialize a diagramação.</p>
        </div>
        <div className="flex gap-2">
           <button onClick={() => setInputText('')} className="px-6 py-3 bg-white border border-gray-100 text-red-400 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-50 transition-all">Limpar</button>
           <button className="px-8 py-3 bg-black text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:scale-105 transition-all">Salvar Projeto</button>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* EDITOR */}
        <div className="lg:col-span-5 space-y-6">
           <div className="bg-white rounded-[40px] border border-gray-100 shadow-sm overflow-hidden flex flex-col h-[600px]">
              <div className="bg-gray-50 p-6 border-b border-gray-100">
                 <h3 className="text-xs font-black uppercase tracking-widest text-gray-400">Editor de Roteiro</h3>
              </div>
              <textarea 
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                className="flex-1 p-8 outline-none font-mono text-sm leading-relaxed resize-none bg-gray-50/20 focus:bg-white transition-all"
                placeholder="Slide 1: Título..."
              />
              <div className="p-6 bg-gray-50 border-t border-gray-100">
                 <p className="text-[10px] font-bold text-gray-400 leading-tight">
                    Dica: Use <span className="text-blue-600">*destaque*</span> para realçar palavras. Comece cada slide com <span className="text-black font-black">Slide X:</span>
                 </p>
              </div>
           </div>
        </div>

        {/* PREVIEW */}
        <div className="lg:col-span-7 flex flex-col gap-8">
           <div className="flex items-center justify-between px-4">
              <div className="flex gap-4">
                 <button 
                  onClick={() => setActiveSlide(Math.max(0, activeSlide - 1))}
                  className="p-4 bg-white border border-gray-100 rounded-2xl hover:bg-black hover:text-white transition-all shadow-sm"
                 >←</button>
                 <button 
                  onClick={() => setActiveSlide(Math.min(slides.length - 1, activeSlide + 1))}
                  className="p-4 bg-white border border-gray-100 rounded-2xl hover:bg-black hover:text-white transition-all shadow-sm"
                 >→</button>
              </div>
              <span className="text-[11px] font-black text-gray-300 uppercase tracking-widest">Slide {activeSlide + 1} de {slides.length}</span>
           </div>

           <div className="bg-gray-200 rounded-[60px] p-20 flex justify-center items-center overflow-hidden min-h-[600px] shadow-inner relative">
              <div className="absolute inset-0 opacity-10 flex items-center justify-center select-none pointer-events-none">
                 <span className="text-[20rem] font-black italic tracking-tighter">PHANT</span>
              </div>
              <div className="w-full max-w-[500px] relative z-10">
                 {slides.length > 0 ? renderSlide(slides[activeSlide]) : (
                    <div className="text-center text-gray-400 font-black uppercase tracking-widest">Roteiro vazio</div>
                 )}
              </div>
           </div>

           <div className="flex gap-4 overflow-x-auto pb-4 custom-scrollbar">
              {slides.map((s, i) => (
                <button 
                  key={s.id}
                  onClick={() => setActiveSlide(i)}
                  className={`shrink-0 w-24 aspect-square rounded-2xl border-2 transition-all flex items-center justify-center text-[10px] font-black uppercase ${activeSlide === i ? 'bg-black text-white border-black scale-105' : 'bg-white border-gray-100 text-gray-300'}`}
                >
                  {s.id}
                </button>
              ))}
           </div>
        </div>
      </div>
    </div>
  );
};

export default CarouselGenerator;
